159	        .filter(f -> f.getComponent().equals(Component.wraptor) || f.getComponent().equals(Component.ext))
160	        .findFirst()
161	        .orElseThrow(() -> new IllegalStateException("No extraction failure found for job id " + id + ". This should not happen!"))
162	        .getFailureCode()
163	        .getCode();
