174	  private boolean isDownloadSuccessfull(Collection<ComponentFailure> failures) {
175	    return failures.stream()
176	        .map(ComponentFailure::getFailureCode)
177	        .noneMatch(FailureCodes.PageFailureCode::isBrowserFailure);
178	  }
