180	  /*
181	   * Retries the job by resubmitting it for processing.
182	   * The `startedAt` timestamp should not be updated,
183	   * otherwise the kill cron job will always consider it as new and not stuck.
184	   */
185	  private ResponseEntity<InfoApiResponse> retryJob(String id) {
186	    Job j = this.jobRepository.findById(id)
187	        .orElseThrow(() -> new IllegalStateException("Job with id " + id + " not found in the DB. This should not happen!"));
188	    PageSpecification spec = PageSpecificationUtils.create(j.getId(), j.getUrl(), j.getPageType(), j.getDownloaderType());
189	    this.rabbit.publishJob(spec, j.getPriority());
190	    return ResponseEntity.noContent().build();
191	  }
