193	  private ResponseEntity<InfoApiResponse> succeedJob(String id) {
194	    log.info("Succeeding job '{}'", id);
195	    if (jobRepository.succeedJob(id) == 1) {
196	      final Optional<Job> job = jobRepository.findById(id);
197	      job.flatMap(Job::getRuntime)
198	          .ifPresent(duration -> log.info("Job '{}' succeeded successfully in {} seconds", id, duration.getSeconds()));
199	      job.ifPresent(j -> sns.sendNotificationIfNeeded(new JobDTO(j), true));
200	      return ResponseEntity.noContent().build();
201	    } else {
202	      final Optional<Job> job = jobRepository.findById(id);
203	      if (job.isEmpty()) {
204	        log.info("Job {} cannot be succeeded, it doesn't exist", id);
205	        return idNotFound();
206	      } else {
207	        log.info("Job '{}' cannot be succeeded, it's not in the RUNNING state", id);
208	        return ResponseEntity.noContent().build();
209	      }
210	    }
211	  }
212	
213	  private ResponseEntity<InfoApiResponse> failJob(String id, String errorCode) {
214	    log.info("Failing job '{}'", id);
215	    if (jobRepository.failJob(id, errorCode) == 1) {
216	      log.info("Job '{}' failed successfully", id);
217	      final Optional<Job> job = jobRepository.findById(id);
218	      job.ifPresent(j -> sns.sendNotificationIfNeeded(new JobDTO(j), false));
219	      return ResponseEntity.noContent().build();
220	    } else {
221	      final Optional<Job> job = jobRepository.findById(id);
222	      if (job.isEmpty()) {
223	        log.info("Job {} cannot be failed, it doesn't exist", id);
224	        return idNotFound();
225	      } else {
226	        log.info("Job '{}' cannot be failed, it's not in the RUNNING state", id);
227	        return ResponseEntity.noContent().build();
228	      }
229	    }
230	  }
231	
232	  private boolean isMetadataJob(final JsonNode jobRes) {
233	    try {
234	      InfoPageResult res = JsonUtils.getMapper().convertValue(jobRes, InfoPageResult.class);
235	      return AnalysisType.METADATA.equals(AnalysisType.fromPageType(PageType.valueOf(res.getType().toUpperCase())));
236	    } catch (Exception e) {
237	      return false;
238	    }
239	  }
240	
241	  private ExtractionResult createNewsResult(final PageResult pageResult, final AnalysisType type) {
242	    return switch (type) {
243	      case ARTICLE -> ArticleResult.builder().articleData(pageResult.getArticleData()).build();
244	      case SECTION -> SectionResult.builder().sectionData(pageResult.getSectionData()).build();
245	      default -> throw new IllegalArgumentException("Type " + type + " is not a news type");
246	    };
247	  }
248	
249	  private ExtractionResult createMetadataResult(final InfoPageResult infoPageRes) {
250	    return MetadataResult.builder().metadata(infoPageRes.getMetadata()).build();
251	  }
252	
253	  private ExtractionResult createMetadataErrorResult(final InfoPageResult infoPageResult) {
254	    if(infoPageResult.getFailures().isEmpty()) {
255	      throw new IllegalArgumentException("No failures found in InfoPageResult");
256	    }
257	    return this.fromComponentFailure(infoPageResult.getFailures().get(0));
258	  }
259	
260	  private ExtractionResult createNewsErrorResult(final PageSpecification spec) {
261	    if(spec.getFailures().isEmpty()) {
262	      throw new IllegalStateException("Given page specification has no failures");
263	    }
264	    return this.fromComponentFailure(spec.getFailures().get(0));
265	  }
266	
267	  private ExtractionResult fromComponentFailure(ComponentFailure componentFailure) {
268	    ExtractionResult res = new ExtractionResult();
269	    res.setErrorCode(componentFailure.getFailureCode().getCode());
270	    res.setErrorExplanation(componentFailure.getFailureCode().getFailureType());
271	    return res;
272	  }
273	
274	}
