package com.meltwater.wrapidity.info.service;

import com.fasterxml.jackson.databind.JsonNode;
import com.meltwater.wrapidity.extractor.model.Component;
import com.meltwater.wrapidity.extractor.model.DomainObjectIdentifier;
import com.meltwater.wrapidity.extractor.util.DomainObjectIdentifierUtils;
import com.meltwater.wrapidity.induction.sourceconfig.*;
import com.meltwater.wrapidity.info.InfoPageResult;
import com.meltwater.wrapidity.info.domain.AnalysisType;
import com.meltwater.wrapidity.info.domain.Job;
import com.meltwater.wrapidity.info.dto.InfoApiResponse;
import com.meltwater.wrapidity.info.dto.JobDTO;
import com.meltwater.wrapidity.info.queues.RabbitMqSender;
import com.meltwater.wrapidity.info.queues.SnsSender;
import com.meltwater.wrapidity.info.repository.JobsRepository;
import com.meltwater.wrapidity.info.results.ArticleResult;
import com.meltwater.wrapidity.info.results.ExtractionResult;
import com.meltwater.wrapidity.info.results.MetadataResult;
import com.meltwater.wrapidity.info.results.SectionResult;
import com.meltwater.wrapidity.info.s3.S3;
import com.meltwater.wrapidity.info.utils.PageSpecificationUtils;
import com.meltwater.wrapidity.util.misc.JsonUtils;
import lombok.AllArgsConstructor;
import lombok.extern.slf4j.Slf4j;
import org.springframework.http.HttpStatus;
import org.springframework.http.ResponseEntity;
import org.springframework.stereotype.Service;

import java.util.Collection;
import java.util.Optional;
import java.util.function.Consumer;

import static com.meltwater.wrapidity.info.utils.ResponseUtils.buildErrorResponse;
import static com.meltwater.wrapidity.info.utils.ResponseUtils.idNotFound;

@Service
@Slf4j
@AllArgsConstructor
public class JobCompleterService {

  private static final String INTERNAL_FAILURE = FailureCodes.SourceFailureCode.IF001.getCode();

  private final JobsRepository jobRepository;
  private final S3 s3;
  private final RabbitMqSender rabbit;
  private final SnsSender sns;

  public ResponseEntity<InfoApiResponse> complete(String s3path) {
    log.info("Completing job with s3path {}", s3path);
    final Optional<JsonNode> optResult = this.s3.getJobResult(s3path);
    if (optResult.isEmpty()) {
      return this.handleMissingJob(s3path);
    }

    final JsonNode res = optResult.get();
    ResponseEntity<InfoApiResponse> completionResponse;
    String id;

    if (this.isMetadataJob(res)) {
      final InfoPageResult infoPageResult = JsonUtils.getMapper().convertValue(res, InfoPageResult.class);
      id = infoPageResult.getId();
      completionResponse = this.handleMetadataJob(id, infoPageResult);
    } else {
      final PageResult pageResult = JsonUtils.getMapper().convertValue(optResult.get(), PageResult.class);
      id = pageResult.getSpecification().getId();
      completionResponse = this.handleNewsJob(id, pageResult);
    }
    log.info("Completion of job '{}' finished. Success: {}", s3path, completionResponse.getStatusCode().is2xxSuccessful());
    return completionResponse;
  }

  private ResponseEntity<InfoApiResponse> handleMissingJob(String s3path) {
    log.error("No job result found for s3path {}. Impossible to complete it!", s3path);
    return buildErrorResponse(HttpStatus.NOT_FOUND,
        "Cannot find the job with path " + s3path + " on s3. Impossible to complete it!");
  }

  private ResponseEntity<InfoApiResponse> handleMetadataJob(String id, InfoPageResult infoPageResult) {
    try {
      AnalysisType type = AnalysisType.fromPageType(PageType.valueOf(infoPageResult.getType().toUpperCase()));
      boolean success = !infoPageResult.isFailure();
      ExtractionResult extRes = success ? this.createMetadataResult(infoPageResult) : this.createMetadataErrorResult(infoPageResult);
      String errorCode = !success ? extRes.getErrorCode() : null;
      if(this.isDownloadSuccessfull(infoPageResult.getFailures())) {
        log.info("Job {} failed with error code {}, retrying it", id, errorCode);
        return this.retryJob(id);
      }
      this.s3.saveResult(type, id, extRes);
      return success ? this.succeedJob(id) : this.failJob(id, errorCode);
    } catch (Exception e) {
      log.error("Error while saving result for company job {}", id, e);
      return this.failJob(id, INTERNAL_FAILURE);
    }
  }

  private ResponseEntity<InfoApiResponse> handleNewsJob(String id, PageResult pageResult) {
    try {
      Job job = this.jobRepository.findById(id)
          .orElseThrow(() -> new IllegalStateException("Job with id " + id + " not found in the DB. This should not happen!"));
      AnalysisType type = job.getPageType();
      boolean success = !PageSpecificationUtils.extractionFailed(pageResult.getSpecification());
      boolean hasHtml = PageSpecificationUtils.hasHtmlSourceCode(pageResult.getSpecification());
      boolean isFirstAttempt = job.getRetryCount() == 0;

      if (success) {
        ExtractionResult newsRes = this.createNewsResult(pageResult, type);
        this.s3.saveResult(type, id, newsRes);
        return this.succeedJob(id);
      } else {
        if (PageSpecificationUtils.isWraptorFailure(pageResult.getSpecification()) && hasHtml && isFirstAttempt) {
          log.info("Wraptor failure detected for job {}. Trying non-llm pipeline", id);
          return this.retryOnSegmenterPipeline(id, pageResult);
        } else if (hasHtml && job.getPriority() < 0 && isFirstAttempt) {
          log.info("Low-priority job {} failed. Trying llm pipeline", id);
          return this.retryOnLlmPipeline(id, pageResult);
        } else {
          ExtractionResult newsRes = this.createNewsErrorResult(pageResult.getSpecification());
          String errorCode = newsRes.getErrorCode();
          if (this.isDownloadSuccessfull(pageResult.getSpecification().getFailures())) {
            log.info("Job {} failed with error code {}, retrying it", id, errorCode);
            return this.retryJob(id);
          }
          this.s3.saveResult(type, id, newsRes);
          return this.failJob(id, errorCode);
        }
      }

    } catch (Exception e) {
      log.error("Error while saving result for news job {}", id, e);
      return this.failJob(id, INTERNAL_FAILURE);
    }
  }

  private ResponseEntity<InfoApiResponse> retryOnSegmenterPipeline(String id, PageResult pageResult) {
    return this.retryOnPipeline(id, pageResult, this.rabbit::publishToSegmenter);
  }

  private ResponseEntity<InfoApiResponse> retryOnLlmPipeline(String id, PageResult pageResult) {
    return this.retryOnPipeline(id, pageResult, this.rabbit::publishToWraptor);
  }

  private ResponseEntity<InfoApiResponse> retryOnPipeline(String id, PageResult pageResult, Consumer<String> rabbitPublisher) {
    String errorCode =  this.getExtractionErrorCode(id, pageResult);
    if (this.jobRepository.addFailure(id, errorCode) != 1) {
      log.error("Error while adding failure to job {}", id);
    }
    if (this.jobRepository.incrementRetryCount(id) != 1) {
      log.error("Could not increment retry count for job {}. Skipping re-queue and failing job instead.", id);
      return this.failJob(id, INTERNAL_FAILURE);
    }
    String briocheS3url = this.createBrioches3url(id, pageResult.getSpecification());
    rabbitPublisher.accept(briocheS3url);
    return ResponseEntity.noContent().build();
  }

  private String getExtractionErrorCode(String id, PageResult pageResult) {
    return pageResult.getSpecification().getFailures()
        .stream()
        .filter(f -> f.getComponent().equals(Component.wraptor) || f.getComponent().equals(Component.ext))
        .findFirst()
        .orElseThrow(() -> new IllegalStateException("No extraction failure found for job id " + id + ". This should not happen!"))
        .getFailureCode()
        .getCode();
  }

  private String createBrioches3url(String jobId, PageSpecification specification) {
    DomainObjectIdentifier doi = DomainObjectIdentifierUtils.getDomainObjectIdentifier(specification);
    String appId = doi.getAppId();
    String runId = doi.getRunId();
    String componentId = Component.brow.name();
    return this.s3.buildFullS3Uri(appId, runId, componentId, jobId);
  }

  private boolean isDownloadSuccessfull(Collection<ComponentFailure> failures) {
    return failures.stream()
        .map(ComponentFailure::getFailureCode)
        .noneMatch(FailureCodes.PageFailureCode::isBrowserFailure);
  }

  /*
   * Retries the job by resubmitting it for processing.
   * The `startedAt` timestamp should not be updated,
   * otherwise the kill cron job will always consider it as new and not stuck.
   */
  private ResponseEntity<InfoApiResponse> retryJob(String id) {
    Job j = this.jobRepository.findById(id)
        .orElseThrow(() -> new IllegalStateException("Job with id " + id + " not found in the DB. This should not happen!"));
    PageSpecification spec = PageSpecificationUtils.create(j.getId(), j.getUrl(), j.getPageType(), j.getDownloaderType());
    this.rabbit.publishJob(spec, j.getPriority());
    return ResponseEntity.noContent().build();
  }

  private ResponseEntity<InfoApiResponse> succeedJob(String id) {
    log.info("Succeeding job '{}'", id);
    if (jobRepository.succeedJob(id) == 1) {
      final Optional<Job> job = jobRepository.findById(id);
      job.flatMap(Job::getRuntime)
          .ifPresent(duration -> log.info("Job '{}' succeeded successfully in {} seconds", id, duration.getSeconds()));
      job.ifPresent(j -> sns.sendNotificationIfNeeded(new JobDTO(j), true));
      return ResponseEntity.noContent().build();
    } else {
      final Optional<Job> job = jobRepository.findById(id);
      if (job.isEmpty()) {
        log.info("Job {} cannot be succeeded, it doesn't exist", id);
        return idNotFound();
      } else {
        log.info("Job '{}' cannot be succeeded, it's not in the RUNNING state", id);
        return ResponseEntity.noContent().build();
      }
    }
  }

  private ResponseEntity<InfoApiResponse> failJob(String id, String errorCode) {
    log.info("Failing job '{}'", id);
    if (jobRepository.failJob(id, errorCode) == 1) {
      log.info("Job '{}' failed successfully", id);
      final Optional<Job> job = jobRepository.findById(id);
      job.ifPresent(j -> sns.sendNotificationIfNeeded(new JobDTO(j), false));
      return ResponseEntity.noContent().build();
    } else {
      final Optional<Job> job = jobRepository.findById(id);
      if (job.isEmpty()) {
        log.info("Job {} cannot be failed, it doesn't exist", id);
        return idNotFound();
      } else {
        log.info("Job '{}' cannot be failed, it's not in the RUNNING state", id);
        return ResponseEntity.noContent().build();
      }
    }
  }

  private boolean isMetadataJob(final JsonNode jobRes) {
    try {
      InfoPageResult res = JsonUtils.getMapper().convertValue(jobRes, InfoPageResult.class);
      return AnalysisType.METADATA.equals(AnalysisType.fromPageType(PageType.valueOf(res.getType().toUpperCase())));
    } catch (Exception e) {
      return false;
    }
  }

  private ExtractionResult createNewsResult(final PageResult pageResult, final AnalysisType type) {
    return switch (type) {
      case ARTICLE -> ArticleResult.builder().articleData(pageResult.getArticleData()).build();
      case SECTION -> SectionResult.builder().sectionData(pageResult.getSectionData()).build();
      default -> throw new IllegalArgumentException("Type " + type + " is not a news type");
    };
  }

  private ExtractionResult createMetadataResult(final InfoPageResult infoPageRes) {
    return MetadataResult.builder().metadata(infoPageRes.getMetadata()).build();
  }

  private ExtractionResult createMetadataErrorResult(final InfoPageResult infoPageResult) {
    if(infoPageResult.getFailures().isEmpty()) {
      throw new IllegalArgumentException("No failures found in InfoPageResult");
    }
    return this.fromComponentFailure(infoPageResult.getFailures().get(0));
  }

  private ExtractionResult createNewsErrorResult(final PageSpecification spec) {
    if(spec.getFailures().isEmpty()) {
      throw new IllegalStateException("Given page specification has no failures");
    }
    return this.fromComponentFailure(spec.getFailures().get(0));
  }

  private ExtractionResult fromComponentFailure(ComponentFailure componentFailure) {
    ExtractionResult res = new ExtractionResult();
    res.setErrorCode(componentFailure.getFailureCode().getCode());
    res.setErrorExplanation(componentFailure.getFailureCode().getFailureType());
    return res;
  }

}

