package com.meltwater.wrapidity.info.service;

import com.meltwater.wrapidity.info.domain.AnalysisType;
import com.meltwater.wrapidity.info.dto.JobDTO;
import com.meltwater.wrapidity.info.results.ArticleResult;
import com.meltwater.wrapidity.info.results.ExtractionResult;
import com.meltwater.wrapidity.util.misc.JsonUtils;
import lombok.SneakyThrows;
import org.junit.jupiter.api.Test;
import org.mockito.ArgumentCaptor;

import java.nio.file.Files;
import java.nio.file.Path;
import java.util.Optional;
import java.util.UUID;

import static com.meltwater.wrapidity.info.domain.AnalysisType.ARTICLE;
import static com.meltwater.wrapidity.info.domain.AnalysisType.METADATA;
import static com.meltwater.wrapidity.info.domain.JobState.*;
import static org.assertj.core.api.Assertions.assertThat;
import static org.mockito.ArgumentMatchers.any;
import static org.mockito.ArgumentMatchers.anyString;
import static org.mockito.Mockito.*;

class JobCompleterServiceTest extends AbstractInfoApiServiceTest {

  @SneakyThrows
  @Test
  void testComplete_metadataJobFinished() {
    var request = createAnalysePageRequest(METADATA, "testAttr");
    String jobId = UUID.randomUUID().toString();
    insertTestJob(request, jobId, RUNNING);

    var s3path = "s3://testBucket/doc.json";
    var s3Payload = Files.readString(Path.of("src/test/resources/controller_v2/metadata_s3_payload.json"));
    s3Payload = s3Payload.replaceAll("\\{\\{objectId}}", jobId);
    var jsonNodeResult = JsonUtils.getMapper().readTree(s3Payload);
    when(s3.getJobResult(s3path)).thenReturn(Optional.of(jsonNodeResult));

    var responseEntity = controller.complete(s3path);

    assertStatusCode(responseEntity, 204);
    assertThat(responseEntity.getBody()).isNull();

    var metadataResponse = assertInductionResultSavedToS3(request.getType(), jobId, ExtractionResult.class);
    assertThat(metadataResponse).isNotNull();

    var jobSentToSns = assertNotificationSentToSns(true);
    assertJobsEqual(jobSentToSns, request, DONE);

    JobDTO completedJobFromDb = findJob(jobId);
    assertJobsEqual(completedJobFromDb, request, DONE);

    verifyNoInteractions(rabbit);
  }

  @SneakyThrows
  @Test
  void testComplete_newsJobFinished() {
    var request = createAnalysePageRequest(ARTICLE, "testAttr");
    String jobId = UUID.randomUUID().toString();
    insertTestJob(request, jobId, RUNNING);

    var s3path = "s3://testBucket/doc.json";
    var s3Payload = Files.readString(Path.of("src/test/resources/controller_v2/article_s3_payload.json"));
    s3Payload = s3Payload.replaceAll("\\{\\{objectId}}", jobId);
    var jsonNodeResult = JsonUtils.getMapper().readTree(s3Payload);
    when(s3.getJobResult(s3path)).thenReturn(Optional.of(jsonNodeResult));

    var responseEntity = controller.complete(s3path);

    assertStatusCode(responseEntity, 204);
    assertThat(responseEntity.getBody()).isNull();

    var articleResponse = assertInductionResultSavedToS3(request.getType(), jobId, ArticleResult.class);
    assertThat(articleResponse).isNotNull();
    assertThat(articleResponse.getArticleData()).isNotNull();
    assertThat(articleResponse.getArticleData().getTitle()).isEqualTo("Top headlines: Canada’s biggest banks at bottom of low-carbon finance ranking");

    var jobSentToSns = assertNotificationSentToSns(true);
    assertJobsEqual(jobSentToSns, request, DONE);

    JobDTO completedJobFromDb = findJob(jobId);
    assertJobsEqual(completedJobFromDb, request, DONE);

    verifyNoInteractions(rabbit);
  }

  @Test
  void testComplete_resultNotfound() {
    var request = createAnalysePageRequest(METADATA, "testAttr");
    String jobId = UUID.randomUUID().toString();
    insertTestJob(request, jobId, RUNNING);

    var s3path = "s3://testBucket/doc.json";
    when(s3.getJobResult(s3path)).thenReturn(Optional.empty());

    var responseEntity = controller.complete(s3path);

    assertError(responseEntity,
        404,
        "Cannot find the job with path " + s3path + " on s3. Impossible to complete it!"
    );

    verify(s3, never()).saveResult(any(), any());
    verify(s3, never()).saveResult(any(), any(), any());
    verifyNoInteractions(rabbit, sns);
  }

  @SneakyThrows
  @Test
  void testComplete_saveResultFails() {
    var request = createAnalysePageRequest(METADATA, "testAttr");
    String jobId = UUID.randomUUID().toString();
    insertTestJob(request, jobId, RUNNING);

    var s3path = "s3://testBucket/doc.json";
    var s3Payload = Files.readString(Path.of("src/test/resources/controller_v2/metadata_s3_payload.json"));
    s3Payload = s3Payload.replaceAll("\\{\\{objectId}}", jobId);
    var jsonNodeResult = JsonUtils.getMapper().readTree(s3Payload);
    when(s3.getJobResult(s3path)).thenReturn(Optional.of(jsonNodeResult));

    when(s3.saveResult(any(), anyString(), any())).thenThrow(new RuntimeException("test ex"));

    var responseEntity = controller.complete(s3path);

    assertStatusCode(responseEntity, 204);
    assertThat(responseEntity.getBody()).isNull();

    var metadataResponse = assertInductionResultSavedToS3(request.getType(), jobId, ExtractionResult.class);
    assertThat(metadataResponse).isNotNull();

    var jobSentToSns = assertNotificationSentToSns(false);
    assertJobsEqual(jobSentToSns, request, FAILED);

    JobDTO failedJobFromDb = findJob(jobId);
    assertJobsEqual(failedJobFromDb, request, FAILED);

    verifyNoInteractions(rabbit);
  }

  private <T> T assertInductionResultSavedToS3(AnalysisType analysisType, String jobId, Class<T> clazz) {
    var captor = ArgumentCaptor.forClass(clazz);
    verify(s3).saveResult(eq(analysisType), eq(jobId), captor.capture());
    return captor.getValue();
  }

}
